	@Test
	void runtimeFeedbackCallbackReportsElapsedReward() throws Exception {
		System.setProperty("rdf4j.optimizer.joinengine.runtimeFeedback.enabled", "true");
		try {
			SPARQLParser parser = new SPARQLParser();
			ParsedQuery parsedQuery = parser.parseQuery(QUERY, null);

			EvaluationStatistics statistics = new EvaluationStatistics();
			JoinEngineConfig config = JoinEngineConfig.defaults();
			RecordingBanditPolicy banditPolicy = new RecordingBanditPolicy();

			QueryJoinOptimizer optimizer = new QueryJoinOptimizer(statistics, false, new EmptyTripleSource(), true,
					config, new DefaultJoinOptimizationEngine(), new DefaultUncertaintyAwareEstimator(),
					new DefaultCostModel(), banditPolicy, OptimizationTraceSink.NOOP);
			optimizer.optimize(parsedQuery.getTupleExpr(), null, null);

			assertTrue(banditPolicy.reports.isEmpty(),
					"Expected no immediate report when runtime feedback mode is enabled");

			Class<?> feedbackClass = Class.forName(
					"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine.JoinEngineRuntimeFeedback");
			Method reportMethod = feedbackClass.getMethod("reportSelectedPlanElapsedMillis", double.class);
			Object accepted = reportMethod.invoke(null, 42.0d);
			assertTrue(Boolean.TRUE.equals(accepted), "Expected runtime feedback callback to accept report");

			assertEquals(1, banditPolicy.reports.size(), "Expected one runtime feedback report");
			ReportedOutcome first = banditPolicy.reports.get(0);
			assertTrue(first.regionFingerprint != null && !first.regionFingerprint.isBlank(),
					"Expected non-empty region fingerprint");
			assertTrue(first.planner != null && !first.planner.isBlank(), "Expected chosen planner");
			assertEquals(-42.0d, first.reward, 0.0001d);
		} finally {
			System.clearProperty("rdf4j.optimizer.joinengine.runtimeFeedback.enabled");
			try {
				Class<?> feedbackClass = Class.forName(
						"org.eclipse.rdf4j.query.algebra.evaluation.optimizer.joinengine.JoinEngineRuntimeFeedback");
				Method clearMethod = feedbackClass.getMethod("clearCurrentThread");
				clearMethod.invoke(null);
			} catch (ReflectiveOperationException ignored) {
				// Runtime feedback class not available yet during red phase.
			}
		}
	}

